    25	func TestDDLFileSource_Load(t *testing.T) {
    26		ddl := `CREATE TABLE Users (
    27			UserId INT64 NOT NULL,
    28			Name STRING(MAX),
    29			Email STRING(256) NOT NULL,
    30			Age INT64,
    31			CreatedAt TIMESTAMP NOT NULL,
    32		) PRIMARY KEY (UserId)`
    33	
    34		dir := t.TempDir()
    35		path := filepath.Join(dir, "schema.sql")
    36		if err := os.WriteFile(path, []byte(ddl), 0o644); err != nil {
    37			t.Fatal(err)
    38		}
    39	
    40		source := NewDDLFileSource(path)
    41		schema, err := source.Load(t.Context())
    42		if err != nil {
    43			t.Fatalf("Load() error = %v", err)
    44		}
    45	
    46		if len(schema.Types) != 1 {
    47			t.Fatalf("expected 1 type, got %d", len(schema.Types))
    48		}
    49	
    50		typ := schema.Types[0]
    51		if typ.Name != "Users" {
    52			t.Errorf("type name = %q, want %q", typ.Name, "Users")
    53		}
    54		if typ.Table != "Users" {
    55			t.Errorf("table name = %q, want %q", typ.Table, "Users")
    56		}
    57	
    58		// Check field count.
    59		if len(typ.Fields) != 5 {
    60			t.Fatalf("expected 5 fields, got %d", len(typ.Fields))
    61		}
    62	
    63		// Check some field mappings.
    64		tests := map[string]struct {
    65			fieldIdx int
    66			name     string
    67			goType   string
    68			baseType string
    69			notNull  bool
